import numpy as np

def augment_img(img: np.ndarray, mode: int) -> np.ndarray:
    # If the image is empty or not 2D, return it unchanged
    if img.size == 0 or img.ndim != 2:
        return img

    if mode == 0:
        return img
    elif mode == 1:
        # Flip upside down, then rotate 90° counterclockwise
        return np.rot90(np.flipud(img), k=1)
    elif mode == 2:
        # Flip upside down only
        return np.flipud(img)
    elif mode == 3:
        # Rotate 270° counterclockwise (or 90° clockwise)
        return np.rot90(img, k=3)
    elif mode == 4:
        # Flip upside down, then rotate 180°
        return np.rot90(np.flipud(img), k=2)
    elif mode == 5:
        # Rotate 90° counterclockwise
        return np.rot90(img, k=1)
    elif mode == 6:
        # Rotate 180°
        return np.rot90(img, k=2)
    elif mode == 7:
        # Flip upside down, then rotate 270° counterclockwise
        return np.rot90(np.flipud(img), k=3)
    else:
        # For any other mode, return the original image
        return img
