import numpy as np

def logbins_numba(lo: float, hi: float, ratio: float, N: int, prepend_zero: bool) -> np.ndarray:
    lo_int = int(lo)
    hi_int = int(hi)

    if ratio != 0 and N == 0:
        N = np.log(hi_int / lo_int) / np.log(ratio)
    if N == 0:
        N = 10
    N = max(1, int(N))

    # Generate logarithmically spaced points
    vals = np.logspace(np.log10(lo_int), np.log10(hi_int), N, base=10)
    vals = np.round(vals).astype(int)
    vals = np.unique(vals)

    if len(vals) == 0:
        return np.array([0], dtype=int) if prepend_zero else np.array([], dtype=int)

    if vals[0] != lo_int:
        vals = np.insert(vals, 0, lo_int)
    if vals[-1] != hi_int:
        vals = np.append(vals, hi_int)

    if prepend_zero:
        vals = np.insert(vals, 0, 0)

    return vals.astype(int)
